+        if excluded_agents.contains(&agent) || estimated_gain < policy.probe_gain_floor {
+            continue;
+        }
+        if candidates.len() >= max_probes || candidates.len() >= budgeted_probe_count {
+            break;
+        }
+        if spent_budget.saturating_add(probe_cost) > max_budget_micros {
